    /**
     * @method
     * @name woo#watchMyTrades
     * @see https://docs.woox.io/#executionreport
     * @see https://docs.woox.io/#algoexecutionreportv2
     * @description watches information on multiple trades made by the user
     * @param {string} symbol unified market symbol of the market orders were made in
     * @param {int} [since] the earliest time in ms to fetch orders for
     * @param {int} [limit] the maximum number of order structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {bool} [params.trigger] true if trigger order
     * @returns {object[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=trade-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchMyTrades(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object trigger = this.safeBool2(parameters, "stop", "trigger", false);
            Object topic = ((Helpers.isTrue((trigger)))) ? "algoexecutionreportv2" : "executionreport";
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("stop", "trigger")));
            Object messageHash = "myTrades";
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                Object market = this.market(symbol);
                symbol = Helpers.GetValue(market, "symbol");
                messageHash = Helpers.add(messageHash, Helpers.add(":", symbol));
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "event", "subscribe" );
                put( "topic", topic );
            }};
            Object message = this.extend(request, parameters);
            Object trades = (this.watchPrivate(messageHash, message)).join();
            if (Helpers.isTrue(this.newUpdates))
            {
                limit = Helpers.callDynamically(trades, "getLimit", new Object[]{symbol, limit});
            }
            return this.filterBySymbolSinceLimit(trades, symbol, since, limit, true);
        });

    }

    public Object parseWsOrder(Object order, Object... optionalArgs)
    {
        //
        //     {
        //         "symbol": "PERP_BTC_USDT",
        //         "clientOrderId": 0,
        //         "orderId": 52952826,
        //         "type": "LIMIT",
        //         "side": "SELL",
        //         "quantity": 0.01,
        //         "price": 22000,
        //         "tradeId": 0,
        //         "executedPrice": 0,
        //         "executedQuantity": 0,
        //         "fee": 0,
        //         "feeAsset": "USDT",
        //         "totalExecutedQuantity": 0,
        //         "status": "NEW",
        //         "reason": '',
        //         "orderTag": "default",
        //         "totalFee": 0,
        //         "visible": 0.01,
        //         "timestamp": 1657515556798,
        //         "reduceOnly": false,
        //         "maker": false
        //     }
        //     {
        //      "symbol": "SPOT_BTC_USDT",
        //      "rootAlgoOrderId": 2573778,
        //      "parentAlgoOrderId": 0,
        //      "algoOrderId": 2573778,
        //      "clientOrderId": 0,
        //      "orderTag": "default",
        //      "algoType": "STOP_LOSS",
        //      "side": "SELL",
        //      "quantity": 0.00011,
        //      "triggerPrice": 98566.67,
        //      "triggerStatus": "USELESS",
        //      "price": 0,
        //      "type": "MARKET",
        //      "triggerTradePrice": 0,
        //      "triggerTime": 0,
        //      "tradeId": 0,
        //      "executedPrice": 0,
        //      "executedQuantity": 0,
        //      "fee": 0,
        //      "reason": "",
        //      "feeAsset": "",
        //      "totalExecutedQuantity": 0,
        //      "averageExecutedPrice": 0,
        //      "totalFee": 0,
        //      "timestamp": 1761030467426,
        //      "visibleQuantity": 0,
        //      "reduceOnly": false,
        //      "triggerPriceType": "MARKET_PRICE",
        //      "positionSide": "BOTH",
        //      "feeCurrency": "",
        //      "totalRebate": 0.0,
        //      "rebateCurrency": "",
        //      "triggered": false,
        //      "maker": false,
        //      "activated": false,
        //      "isTriggered": false,
        //      "isMaker": false,
        //      "isActivated": false,
        //      "rootAlgoStatus": "NEW",
        //      "algoStatus": "NEW"
        // }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object orderId = this.safeString2(order, "orderId", "algoOrderId");
        Object marketId = this.safeString(order, "symbol");
        market = this.market(marketId);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object timestamp = this.safeInteger(order, "timestamp");
        Object fee = new java.util.HashMap<String, Object>() {{
            put( "cost", WooCore.this.safeString(order, "totalFee") );
            put( "currency", WooCore.this.safeString(order, "feeAsset") );
        }};
        Object priceString = this.safeString(order, "price");
        Object price = this.safeNumber(order, "price");
        Object avgPrice = this.safeNumber(order, "avgPrice");
        if (Helpers.isTrue(Helpers.isTrue(Precise.stringEq(priceString, "0")) && Helpers.isTrue((!Helpers.isEqual(avgPrice, null)))))
        {
            price = avgPrice;
        }
        Object amount = this.safeString(order, "quantity");
        Object side = this.safeStringLower(order, "side");
        Object type = this.safeStringLower(order, "type");
        Object filled = this.safeString2(order, "totalExecutedQuantity", "executed");
        Object rawStatus = this.safeString2(order, "status", "algoStatus");
        Object status = this.parseOrderStatus(rawStatus);
        Object trades = null;
        Object clientOrderId = this.safeString(order, "clientOrderId");
        Object triggerPrice = this.safeString(order, "triggerPrice");
        final Object finalPrice = price;
        final Object finalAvgPrice = avgPrice;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "info", order );
            put( "symbol", symbol );
            put( "id", orderId );
            put( "clientOrderId", clientOrderId );
            put( "timestamp", timestamp );
            put( "datetime", WooCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", timestamp );
            put( "type", type );
            put( "timeInForce", null );
            put( "postOnly", null );
            put( "side", side );
            put( "price", finalPrice );
            put( "stopPrice", triggerPrice );
            put( "triggerPrice", triggerPrice );
            put( "reduceOnly", WooCore.this.safeBool(order, "reduceOnly") );
            put( "amount", amount );
            put( "cost", null );
            put( "average", finalAvgPrice );
            put( "filled", filled );
            put( "remaining", null );
            put( "status", status );
            put( "fee", fee );
            put( "trades", trades );
        }});
    }

    public void handleOrderUpdate(Client client, Object message)
    {
        //
        //     {
        //         "topic": "executionreport",
        //         "ts": 1657515556799,
        //         "data": {
        //             "symbol": "PERP_BTC_USDT",
        //             "clientOrderId": 0,
        //             "orderId": 52952826,
        //             "type": "LIMIT",
        //             "side": "SELL",
        //             "quantity": 0.01,
        //             "price": 22000,
        //             "tradeId": 0,
        //             "executedPrice": 0,
        //             "executedQuantity": 0,
        //             "fee": 0,
        //             "feeAsset": "USDT",
        //             "totalExecutedQuantity": 0,
        //             "status": "NEW",
        //             "reason": '',
        //             "orderTag": "default",
        //             "totalFee": 0,
        //             "visible": 0.01,
        //             "timestamp": 1657515556799,
        //             "reduceOnly": false,
        //             "maker": false
        //         }
        //     }
        //
        Object topic = this.safeString(message, "topic");
        Object data = this.safeValue(message, "data");
        if (Helpers.isTrue(Helpers.isArray(data)))
        {
            // algoexecutionreportv2
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
            {
                Object order = Helpers.GetValue(data, i);
                Object tradeId = this.omitZero(this.safeString(data, "tradeId"));
                if (Helpers.isTrue(!Helpers.isEqual(tradeId, null)))
                {
                    this.handleMyTrade(client, order);
                }
                this.handleOrder(client, order, topic);
            }
        } else
        {
            // executionreport
            Object tradeId = this.omitZero(this.safeString(data, "tradeId"));
            if (Helpers.isTrue(!Helpers.isEqual(tradeId, null)))
            {
                this.handleMyTrade(client, data);
            }
            this.handleOrder(client, data, topic);
        }
    }

    public void handleOrder(Client client, Object message, Object topic)
    {
        Object parsed = this.parseWsOrder(message);
        Object symbol = this.safeString(parsed, "symbol");
        Object orderId = this.safeString(parsed, "id");
        if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
        {
            if (Helpers.isTrue(Helpers.isEqual(this.orders, null)))
            {
                Object limit = this.safeInteger(this.options, "ordersLimit", 1000);
                this.orders = new ArrayCache.ArrayCacheBySymbolById(((Number)limit).intValue());
            }
            Object cachedOrders = this.orders;
            Object orders = this.safeValue(((io.github.ccxt.ws.ArrayCache)cachedOrders).hashmap, symbol, new java.util.HashMap<String, Object>() {{}});
            Object order = this.safeValue(orders, orderId);
            if (Helpers.isTrue(!Helpers.isEqual(order, null)))
            {
                Object fee = this.safeValue(order, "fee");
                if (Helpers.isTrue(!Helpers.isEqual(fee, null)))
                {
                    Helpers.addElementToObject(parsed, "fee", fee);
                }
                Object fees = this.safeValue(order, "fees");
                if (Helpers.isTrue(!Helpers.isEqual(fees, null)))
                {
                    Helpers.addElementToObject(parsed, "fees", fees);
                }
                Helpers.addElementToObject(parsed, "trades", this.safeValue(order, "trades"));
                Helpers.addElementToObject(parsed, "timestamp", this.safeInteger(order, "timestamp"));
                Helpers.addElementToObject(parsed, "datetime", this.safeString(order, "datetime"));
            }
            Helpers.callDynamically(cachedOrders, "append", new Object[]{parsed});
            client.resolve(this.orders, topic);
            Object messageHashSymbol = Helpers.add(Helpers.add(topic, ":"), symbol);
            client.resolve(this.orders, messageHashSymbol);
        }
    }

    public void handleMyTrade(Client client, Object message)
    {
        //
        //    {
        //     "msgType": 0,  // execution report
        //     "symbol": "SPOT_BTC_USDT",
        //     "clientOrderId": 0,
        //     "orderId": 54774393,
        //     "type": "MARKET",
        //     "side": "BUY",
        //     "quantity": 0.0,
        //     "price": 0.0,
        //     "tradeId": 56201985,
        //     "executedPrice": 23534.06,
        //     "executedQuantity": 0.00040791,
        //     "fee": 2.1E-7,
        //     "feeAsset": "BTC",
        //     "totalExecutedQuantity": 0.00040791,
        //     "avgPrice": 23534.06,
        //     "status": "FILLED",
        //     "reason": "",
        //     "orderTag": "default",
        //     "totalFee": 2.1E-7,
        //     "feeCurrency": "BTC",
        //     "totalRebate": 0,
        //     "rebateCurrency": "USDT",
        //     "visible": 0.0,
        //     "timestamp": 1675406261689,
        //     "reduceOnly": false,
        //     "maker": false
        //   }
        //
        Object myTrades = this.myTrades;
        if (Helpers.isTrue(Helpers.isEqual(myTrades, null)))
        {
            Object limit = this.safeInteger(this.options, "tradesLimit", 1000);
            myTrades = new ArrayCache.ArrayCacheBySymbolById(((Number)limit).intValue());
        }
        Object trade = this.parseWsTrade(message);
        Helpers.callDynamically(myTrades, "append", new Object[]{trade});
        Object messageHash = Helpers.add("myTrades:", Helpers.GetValue(trade, "symbol"));
        client.resolve(myTrades, messageHash);
        messageHash = "myTrades";
        client.resolve(myTrades, messageHash);
    }

    /**
     * @method
     * @name woo#watchPositions
     * @see https://docs.woox.io/#position-push
     * @description watch all open positions
     * @param {string[]} [symbols] list of unified market symbols
     * @param {int} [since] timestamp in ms of the earliest position to fetch
     * @param {int} [limit] the maximum number of positions to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [position structure]{@link https://docs.ccxt.com/en/latest/manual.html#position-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchPositions(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object messageHashes = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            symbols = this.marketSymbols(symbols);
            if (!Helpers.isTrue(this.isEmpty(symbols)))
            {
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(symbols)); i++)
                {
                    Object symbol = Helpers.GetValue(symbols, i);
                    ((java.util.List<Object>)messageHashes).add(Helpers.add("positions::", symbol));
                }
            } else
            {
                ((java.util.List<Object>)messageHashes).add("positions");
            }
            Object url = Helpers.add(Helpers.add(Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "ws"), "private"), "/"), this.uid);
            Client client = this.client(url);
            this.setPositionsCache(client, symbols);
            Object fetchPositionsSnapshot = this.handleOption("watchPositions", "fetchPositionsSnapshot", true);
            Object awaitPositionsSnapshot = this.handleOption("watchPositions", "awaitPositionsSnapshot", true);
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(fetchPositionsSnapshot) && Helpers.isTrue(awaitPositionsSnapshot)) && Helpers.isTrue(Helpers.isEqual(this.positions, null))))
            {
                Object snapshot = client.future("fetchPositionsSnapshot").getFuture().join();
                return this.filterBySymbolsSinceLimit(snapshot, symbols, since, limit, true);
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "event", "subscribe" );
                put( "topic", "position" );
            }};
            Object newPositions = (this.watchPrivateMultiple(messageHashes, request, parameters)).join();
            if (Helpers.isTrue(this.newUpdates))
            {
                return newPositions;
            }
            return this.filterBySymbolsSinceLimit(this.positions, symbols, since, limit, true);
        });

    }

    public void setPositionsCache(Client client, Object type, Object... optionalArgs)
    {
        Object symbols = Helpers.getArg(optionalArgs, 0, null);
        Object fetchPositionsSnapshot = this.handleOption("watchPositions", "fetchPositionsSnapshot", false);
        if (Helpers.isTrue(fetchPositionsSnapshot))
        {
            Object messageHash = "fetchPositionsSnapshot";
            if (!Helpers.isTrue((Helpers.inOp(client.futures, messageHash))))
            {
                client.future((String)messageHash);
                this.spawn(() -> { try { this.loadPositionsSnapshot(client, messageHash); } catch(Exception _e) { throw new RuntimeException(_e); } });
            }
        } else
        {
            this.positions = new ArrayCache.ArrayCacheBySymbolBySide();
        }
    }

    public java.util.concurrent.CompletableFuture<Object> loadPositionsSnapshot(Client client, Object messageHash2)
    {
        final Object messageHash3 = messageHash2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object messageHash = messageHash3;
            Object positions = (this.fetchPositionsAsync()).join();
            this.positions = new ArrayCache.ArrayCacheBySymbolBySide();
            Object cache = this.positions;
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(positions)); i++)
            {
                Object position = Helpers.GetValue(positions, i);
                Object contracts = this.safeNumber(position, "contracts", 0);
                if (Helpers.isTrue(Helpers.isGreaterThan(contracts, 0)))
                {
                    Helpers.callDynamically(cache, "append", new Object[]{position});
                }
            }
            // don't remove the future from the .futures cache
            if (Helpers.isTrue(Helpers.inOp(client.futures, messageHash)))
            {
                io.github.ccxt.ws.Future future = (io.github.ccxt.ws.Future)Helpers.GetValue(client.futures, messageHash);
                ((io.github.ccxt.ws.Future)future).resolve(cache);
                client.resolve(cache, "positions");
            }
            return null;
        });

    }

    public void handlePositions(Client client, Object message)
    {
        //
        //    {
        //        "topic":"position",
        //        "ts":1705292345255,
        //        "data":{
        //           "positions":{
        //              "PERP_LTC_USDT":{
        //                 "holding":1,
        //                 "pendingLongQty":0,
        //                 "pendingShortQty":0,
        //                 "averageOpenPrice":71.53,
        //                 "pnl24H":0,
        //                 "fee24H":0.07153,
        //                 "settlePrice":71.53,
        //                 "markPrice":71.32098452065145,
        //                 "version":7886,
        //                 "openingTime":1705292304267,
        //                 "pnl24HPercentage":0,
        //                 "adlQuantile":1,
        //                 "positionSide":"BOTH"
        //              }
        //           }
        //        }
        //    }
        //
        Object data = this.safeValue(message, "data", new java.util.HashMap<String, Object>() {{}});
        Object rawPositions = this.safeValue(data, "positions", new java.util.HashMap<String, Object>() {{}});
        Object postitionsIds = Helpers.objectKeys(rawPositions);
        if (Helpers.isTrue(Helpers.isEqual(this.positions, null)))
        {
            this.positions = new ArrayCache.ArrayCacheBySymbolBySide();
        }
        Object cache = this.positions;
        Object newPositions = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(postitionsIds)); i++)
        {
            Object marketId = Helpers.GetValue(postitionsIds, i);
            Object market = this.safeMarket(marketId);
            Object rawPosition = Helpers.GetValue(rawPositions, marketId);
            Object position = this.parsePosition(rawPosition, market);
            ((java.util.List<Object>)newPositions).add(position);
            Helpers.callDynamically(cache, "append", new Object[]{position});
            Object messageHash = Helpers.add("positions::", Helpers.GetValue(market, "symbol"));
            client.resolve(position, messageHash);
        }
        client.resolve(newPositions, "positions");
    }

